class Solution:
    def finalPositionOfSnake(self, n: int, commands: List[str]) -> int:
        position = 0
        for cmd in commands:
            if cmd == "UP":
                position -= n
            elif cmd == "RIGHT":
                position += 1
            elif cmd == "DOWN":
                position += n
            elif cmd == "LEFT":
                position -= 1
        return position
